import type { TKeyValueMap } from '../../util';

import { createContextHook } from '@universe-design/react-utilities';
import type { UseControlledStateSetState } from '@universe-design/react-utilities';
import type { CheckedType, CheckStrictlyKeys } from '../interface';

export interface ITreeCheckedContext {
  checkedCache: Map<string, CheckedType>;
  checkedSet: TKeyValueMap<boolean>;
  setCheckedKeys: UseControlledStateSetState<CheckStrictlyKeys | string[]>;
  toggleChecked: (key: string) => void;
}

const { useContext: useTreeCheckedContext, Provider: TreeCheckedProvider } = createContextHook<
  ITreeCheckedContext | undefined
>('TreeCheckedContext', {
  strict: false,
  defaultValue: undefined,
});

export { useTreeCheckedContext, TreeCheckedProvider };
